                disabled: (!this.value.trim() && this.attachments.length === 0) || this.processingFiles,
                children: html `<div style="transform: rotate(-45deg)">${icon(Send, "sm")}</div>`,
                className: "h-8 w-8",
            })}
								`}
					</div>
				</div>
			</div>
		`;
